    RequestID  string
    Err       error // underlying error
}

func (e *PaymentError) Error() string {
    return fmt.Sprintf("payment error (%s): %v", e.Code, e.Err)
}

func (e *PaymentError) Unwrap() error {
    return e.Err
}

